import{_ as t,o as a,c as s,a2 as i}from"./chunks/framework.CsxL8ROK.js";const u=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"quick-start.md","filePath":"quick-start.md"}'),l={name:"quick-start.md"};function o(r,e,n,p,h,c){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><p>Get your first AI code review in under 10 minutes.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>A GitHub account with permission to create GitHub Apps</li><li>A <a href="https://vercel.com" target="_blank" rel="noreferrer">Vercel</a> account (free tier works)</li><li>An <a href="https://platform.openai.com" target="_blank" rel="noreferrer">OpenAI</a> API key with access to GPT-5</li></ul><h2 id="step-1-—-create-a-github-app" tabindex="-1">Step 1 — Create a GitHub App <a class="header-anchor" href="#step-1-—-create-a-github-app" aria-label="Permalink to &quot;Step 1 — Create a GitHub App&quot;">​</a></h2><ol><li>Go to <strong>Settings → Developer settings → GitHub Apps → New GitHub App</strong></li><li>Set the app name (e.g. <code>my-review-bot</code>)</li><li>Set <strong>Webhook URL</strong> to a placeholder for now (<code>https://example.com</code>) — you&#39;ll update this after deploy</li><li>Set <strong>Webhook secret</strong> to a random string — save it, you&#39;ll need it later</li><li>Grant these permissions: <ul><li><strong>Pull requests</strong>: Read and write</li><li><strong>Contents</strong>: Read-only</li><li><strong>Metadata</strong>: Read-only</li><li><strong>Issues</strong>: Read-only</li></ul></li><li>Subscribe to these events: <ul><li><strong>Pull request</strong></li><li><strong>Issue comment</strong></li></ul></li><li>Click <strong>Create GitHub App</strong></li><li>Note the <strong>App ID</strong> shown at the top of the app settings page</li><li>Scroll to <strong>Private keys</strong> and click <strong>Generate a private key</strong> — save the downloaded <code>.pem</code> file</li></ol><h2 id="step-2-—-deploy-to-vercel" tabindex="-1">Step 2 — Deploy to Vercel <a class="header-anchor" href="#step-2-—-deploy-to-vercel" aria-label="Permalink to &quot;Step 2 — Deploy to Vercel&quot;">​</a></h2><ol><li>Fork this repo</li><li>Go to <a href="https://vercel.com/new" target="_blank" rel="noreferrer">vercel.com/new</a> and import your fork</li><li>Set framework preset to <strong>Other</strong></li><li>Add the environment variables (see <a href="/codex-review-bot/configuration.html">Configuration</a> for all options):</li></ol><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GITHUB_APP_ID=&lt;your app ID&gt;</span></span>
<span class="line"><span>GITHUB_APP_PRIVATE_KEY=&quot;-----BEGIN RSA PRIVATE KEY-----\\n...\\n-----END RSA PRIVATE KEY-----&quot;</span></span>
<span class="line"><span>GITHUB_WEBHOOK_SECRET=&lt;your webhook secret&gt;</span></span>
<span class="line"><span>OPENAI_API_KEY=sk-...</span></span>
<span class="line"><span>REVIEW_ENABLED=true</span></span></code></pre></div><ol start="5"><li>Click <strong>Deploy</strong></li><li>Copy the production URL (e.g. <code>https://my-review-bot.vercel.app</code>)</li></ol><h2 id="step-3-—-point-the-webhook-at-vercel" tabindex="-1">Step 3 — Point the webhook at Vercel <a class="header-anchor" href="#step-3-—-point-the-webhook-at-vercel" aria-label="Permalink to &quot;Step 3 — Point the webhook at Vercel&quot;">​</a></h2><ol><li>Back in your GitHub App settings, set the <strong>Webhook URL</strong> to: <code>https://my-review-bot.vercel.app/api/github/webhook</code></li><li>Save changes</li></ol><h2 id="step-4-—-install-the-app-on-a-repo" tabindex="-1">Step 4 — Install the app on a repo <a class="header-anchor" href="#step-4-—-install-the-app-on-a-repo" aria-label="Permalink to &quot;Step 4 — Install the app on a repo&quot;">​</a></h2><ol><li>In your GitHub App settings, click <strong>Install App</strong></li><li>Select the repositories you want to review</li></ol><h2 id="step-5-—-trigger-your-first-review" tabindex="-1">Step 5 — Trigger your first review <a class="header-anchor" href="#step-5-—-trigger-your-first-review" aria-label="Permalink to &quot;Step 5 — Trigger your first review&quot;">​</a></h2><p>On any open pull request in an installed repo, comment:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/codex-review</span></span></code></pre></div><p>The bot will reply with a structured review within 10–30 seconds depending on PR size.</p><h2 id="local-development" tabindex="-1">Local development <a class="header-anchor" href="#local-development" aria-label="Permalink to &quot;Local development&quot;">​</a></h2><p>Use <a href="https://smee.io" target="_blank" rel="noreferrer">smee.io</a> to receive webhooks locally:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> smee-client</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">smee</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://smee.io/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">your-channe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">l</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --target</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:3000/api/github/webhook</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div>`,21)])])}const k=t(l,[["render",o]]);export{u as __pageData,k as default};
